const raw = $input.first().json.text || $input.first().json.message?.content || '{}';
let params;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  params = match ? JSON.parse(match[0]) : {};
} catch(e) { params = {}; }

// Also accept direct params from API
const input = $('Start').first().json;
params.gross_salary = params.gross_salary || input.gross_salary || null;
params.num_dependents = params.num_dependents ?? input.num_dependents ?? 0;
params.region = params.region || input.region || 'I';
params.income_type = params.income_type || input.income_type || 'salary';
params.revenue = params.revenue || input.revenue || null;
params.message = input.message;

return [{ json: params }];

const p = $input.first().json;
const salary = p.gross_salary;
const npt = p.num_dependents || 0;
const region = p.region || 'I';

if (!salary || salary <= 0) {
  return [{ json: { error: true, answer: 'Vui lòng cho biết mức lương gross/tháng để tính thuế.', agent: 'calculator' } }];
}

// Constants 2026
const BHXH_CEIL = 46800000;
const BHTN_CEIL = { I: 106200000, II: 94600000, III: 82800000, IV: 74000000 };
const PERSONAL = 15500000;
const DEPENDENT = 6200000;
const BRACKETS = [
  { limit: 10000000, rate: 0.05, name: 'Bậc 1' },
  { limit: 30000000, rate: 0.10, name: 'Bậc 2' },
  { limit: 60000000, rate: 0.20, name: 'Bậc 3' },
  { limit: 100000000, rate: 0.30, name: 'Bậc 4' },
  { limit: Infinity, rate: 0.35, name: 'Bậc 5' },
];

const steps = [];

// Step 1: Thu nhập chịu thuế
steps.push({ step: 1, label: 'Thu nhập chịu thuế', value: salary, formula: `${(salary/1000000).toFixed(1)} triệu/tháng` });

// Step 2: BHBB
const bhxh = Math.min(salary, BHXH_CEIL) * 0.08;
const bhyt = Math.min(salary, BHXH_CEIL) * 0.015;
const bhtnCeil = BHTN_CEIL[region] || BHTN_CEIL['I'];
const bhtn = Math.min(salary, bhtnCeil) * 0.01;
const totalBH = bhxh + bhyt + bhtn;

steps.push({ step: 2, label: 'BHXH (8%)', value: -bhxh, formula: `min(${(salary/1e6).toFixed(1)}tr, ${BHXH_CEIL/1e6}tr) × 8%`, note: salary > BHXH_CEIL ? `Vượt trần BHXH ${BHXH_CEIL/1e6}tr` : null });
steps.push({ step: 2, label: 'BHYT (1.5%)', value: -bhyt, formula: `min(${(salary/1e6).toFixed(1)}tr, ${BHXH_CEIL/1e6}tr) × 1.5%` });
steps.push({ step: 2, label: `BHTN (1%) - Vùng ${region}`, value: -bhtn, formula: `min(${(salary/1e6).toFixed(1)}tr, ${bhtnCeil/1e6}tr) × 1%` });
steps.push({ step: 2, label: 'Tổng BHBB', value: -totalBH, formula: `${(totalBH).toLocaleString('vi-VN')} VNĐ` });

// Step 3-4: Giảm trừ
steps.push({ step: 3, label: 'Giảm trừ bản thân', value: -PERSONAL, formula: '15.500.000/tháng (NQ 110/2025)' });
const nptDeduction = npt * DEPENDENT;
steps.push({ step: 4, label: `Giảm trừ NPT (${npt} người)`, value: -nptDeduction, formula: `${npt} × 6.200.000` });

// Step 5: TNTT
const tntt = Math.max(0, salary - totalBH - PERSONAL - nptDeduction);
steps.push({ step: 5, label: 'Thu nhập tính thuế', value: tntt, formula: `${(salary/1e6).toFixed(1)}tr - ${(totalBH/1e6).toFixed(2)}tr - ${PERSONAL/1e6}tr - ${(nptDeduction/1e6).toFixed(1)}tr` });

// Step 6-7: Tính thuế
let totalTax = 0;
let remaining = tntt;
let prevLimit = 0;
const taxBreakdown = [];

if (tntt <= 0) {
  steps.push({ step: 6, label: 'Thuế TNCN', value: 0, formula: 'TNTT ≤ 0 → Không phải nộp thuế' });
} else {
  for (const bracket of BRACKETS) {
    if (remaining <= 0) break;
    const taxable = Math.min(remaining, bracket.limit - prevLimit);
    const tax = taxable * bracket.rate;
    totalTax += tax;
    remaining -= taxable;
    taxBreakdown.push({ bracket: bracket.name, range: `${(prevLimit/1e6).toFixed(0)}-${bracket.limit === Infinity ? '∞' : (bracket.limit/1e6).toFixed(0)}tr`, rate: `${bracket.rate*100}%`, taxable, tax });
    steps.push({ step: 6, label: `${bracket.name}: ${(taxable).toLocaleString('vi-VN')} × ${bracket.rate*100}%`, value: tax, formula: `${(tax).toLocaleString('vi-VN')} VNĐ` });
    prevLimit = bracket.limit;
  }
  steps.push({ step: 7, label: 'Tổng thuế TNCN/tháng', value: totalTax, formula: `${(totalTax).toLocaleString('vi-VN')} VNĐ` });
}

const effectiveRate = salary > 0 ? (totalTax / salary * 100) : 0;

// Step 8
steps.push({ step: 8, label: 'Khuyên đối soát', value: null, formula: 'Đối soát lại bằng Excel hoặc eTax Mobile' });

// Compare 2025
const BRACKETS_2025 = [
  { limit: 5000000, rate: 0.05 }, { limit: 10000000, rate: 0.10 },
  { limit: 18000000, rate: 0.15 }, { limit: 32000000, rate: 0.20 },
  { limit: 52000000, rate: 0.25 }, { limit: 80000000, rate: 0.30 },
  { limit: Infinity, rate: 0.35 },
];
const tntt2025 = Math.max(0, salary - totalBH - 11000000 - npt * 4400000);
let tax2025 = 0; let rem2025 = tntt2025; let prev2025 = 0;
for (const b of BRACKETS_2025) {
  if (rem2025 <= 0) break;
  const t = Math.min(rem2025, b.limit - prev2025);
  tax2025 += t * b.rate;
  rem2025 -= t;
  prev2025 = b.limit;
}

return [{ json: {
  agent: 'calculator',
  calculation_steps: steps,
  tax_breakdown: taxBreakdown,
  total_tax: totalTax,
  total_tax_year: totalTax * 12,
  effective_rate: Math.round(effectiveRate * 100) / 100,
  net_salary: salary - totalBH - totalTax,
  comparison_2025: { tax_2025: Math.round(tax2025), tax_2026: Math.round(totalTax), saved: Math.round(tax2025 - totalTax), saved_year: Math.round((tax2025 - totalTax) * 12) },
  params: { salary, npt, region },
  disclaimer: '⚠️ Kết quả tham khảo. Căn cứ: Luật 109/2025/QH15, NQ 110/2025. Đối soát lại bằng Excel hoặc eTax.'
} }];

const p = $input.first().json;
const revenue = p.revenue;
const sector = p.business_sector || 'other';

if (!revenue || revenue <= 0) {
  return [{ json: { error: true, answer: 'Vui lòng cho biết doanh thu/năm để tính thuế.', agent: 'calculator' } }];
}

const RATES = {
  'goods': { gtgt: 0.01, tncn: 0.005, label: 'Phân phối hàng hóa' },
  'manufacturing': { gtgt: 0.03, tncn: 0.015, label: 'Sản xuất, vận tải' },
  'service': { gtgt: 0.05, tncn: 0.02, label: 'Dịch vụ' },
  'digital': { gtgt: 0.05, tncn: 0.05, label: 'Nội dung số' },
  'rental': { gtgt: 0.05, tncn: 0.05, label: 'Cho thuê tài sản' },
  'other': { gtgt: 0.01, tncn: 0.01, label: 'Khác' },
};
const rate = RATES[sector] || RATES['other'];

let result;
if (revenue <= 1000000000) {
  result = { answer: `Doanh thu ${(revenue/1e6).toFixed(0)} triệu/năm ≤ 1 tỷ → **MIỄN THUẾ** hoàn toàn (NĐ 141/2026/NĐ-CP).\nChỉ cần kê khai doanh thu 1 lần/năm (trước 31/01 năm sau).`, total_tax: 0, agent: 'calculator' };
} else if (revenue <= 3000000000) {
  const gtgt = revenue * rate.gtgt;
  const tncn = revenue * rate.tncn;
  result = { answer: `DT ${(revenue/1e9).toFixed(1)} tỷ (ngành: ${rate.label}):\n- Thuế GTGT: ${(gtgt).toLocaleString('vi-VN')} (${rate.gtgt*100}%)\n- Thuế TNCN: ${(tncn).toLocaleString('vi-VN')} (${rate.tncn*100}%)\n- **Tổng: ${(gtgt+tncn).toLocaleString('vi-VN')} VNĐ/năm**`, total_tax: gtgt+tncn, agent: 'calculator' };
} else {
  const taxRate = revenue > 50000000000 ? 0.20 : 0.17;
  result = { answer: `DT ${(revenue/1e9).toFixed(1)} tỷ → Tính thuế theo lợi nhuận (DT-CP) × ${taxRate*100}%.\nCần có sổ sách kế toán đầy đủ. Khuyến nghị tham vấn kế toán chuyên nghiệp.`, total_tax: null, agent: 'calculator' };
}

result.disclaimer = '⚠️ Căn cứ: NĐ 141/2026, NĐ 68/2026. Kiểm tra tại gdt.gov.vn';
return [{ json: result }];

// Format final output with AI
const result = $input.first().json;
if (result.error) return [{ json: result }];
return [{ json: result }];
